You can copy the code below, save it as an `.html` file, and open it in your browser to see the 3D model.

### Option 1: Interactive 3D House (Three.js)
This code creates a low-poly house with a roof, walls, a door, and a window. You can rotate it with your mouse.

1.  Copy the code below.
2.  Save it as `house.html`.
3.  Open the file in Chrome, Firefox, or Edge.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate • Scroll to Zoom</div>
    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xE0E0E0 }); // White walls
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const grassMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 }); // Green grass
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x5D4037 }); // Dark wood
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMat);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Walls
        const wallGeo = new THREE.BoxGeometry(10, 6, 8);
        const walls = new THREE.Mesh(wallGeo, wallMat);
        walls.position.y = 3;
        walls.castShadow = true;
        walls.receiveShadow = true;
        houseGroup.add(walls);

        // Roof
        const roofGeo = new THREE.ConeGeometry(9, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 2, 4.1); // Slightly in front of wall
        door.castShadow = true;
        houseGroup.add(door);

        // Window
        const winGeo = new THREE.BoxGeometry(2, 2, 0.1);
        const windowMesh = new THREE.Mesh(winGeo, windowMat);
        windowMesh.position.set(0, 5, 4.05);
        houseGroup.add(windowMesh);

        // Chimney
        const chimGeo = new THREE.BoxGeometry(1, 3, 1);
        const chimney = new THREE.Mesh(chimGeo, wallMat);
        chimney.position.set(4, 9, 0);
        chimney.castShadow = true;
        houseGroup.add(chimney);

        scene.add(houseGroup);

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Option 2: Python (Blender API)
If you prefer a Python script to generate a 3D file (`.blend`) that you can open in Blender software, use this script:

```python
import bpy
from mathutils import Vector

# Clear existing objects
bpy.ops.object.select_all(action='SELECT')
bpy.ops.object.delete(use_global=False)

# Create a simple house
# 1. Floor
bpy.ops.mesh.primitive_cube_add(size=10, location=(0, 0, -0.5))
floor = bpy.context.active_object
floor.name = "Floor"
floor.scale = (10, 10, 1)

# 2. Walls
bpy.ops.mesh.primitive_cube_add(size=10, location=(0, 0, 3))
walls = bpy.context.active_object
walls.name = "Walls"
walls.scale = (10, 6, 8)

# 3. Roof (Cone)
bpy.ops.mesh.primitive_cone_add(radius1=9, depth=4, location=(0, 0, 8))
roof = bpy.context.active_object
roof.name = "Roof"
roof.rotation_euler = (0, 0, 0) # Adjust rotation as needed
roof.scale = (1, 1, 1)

# 4. Door
bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 2, 4.1))
door = bpy.context.active_object
door.name = "Door"
door.scale = (2, 4, 0.2)

# 5. Window
bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 5, 4.05))
window = bpy.context.active_object
window.name = "Window"
window.scale = (2, 2, 0.1)

# 6. Materials
for obj in bpy.data.objects:
    mat = bpy.data.materials.new(name=obj.name + " Mat")
    obj.data.materials.append(mat)

# 7. Save the file
bpy.ops.wm.save_as_mainfile(filepath="C:/Users/Public/3D_House.blend")
print("House saved to C:/Users/Public/3D_House.blend")
```

### How to use the Python script:
1.  Install Blender.
2.  Install the Python module: `pip install bpy`.
3.  Run the script
